  function targets(p){const kg=p.currentWeight*.453592,cm=(p.heightFt*12+p.heightIn)*2.54,bmr=10*kg+6.25*cm-5*p.age+(p.sex==='male'?5:-161),maintenance=bmr*Number(p.activity),floor=p.sex==='male'?1500:1200,calories=round(clamp(maintenance-Number(p.pace)*500,floor,maintenance-150),25),protein=round(clamp(kg*1.8,90,220),5),fat=round(calories*.27/9,5),carbs=Math.max(50,round((calories-protein*4-fat*9)/4,5));return{calories,protein,fat,carbs,maintenance:round(maintenance,25),bmr:round(bmr)}}
