  async function handlePin(e){e.preventDefault();const pin=$('#unlockPin').value,mode=e.target.dataset.mode,error=$('#pinError'),btn=$('#unlockBtn');clearTimeout(pinAutoTimer);if(btn.disabled)return;error.classList.add('hidden');if(mode==='create'&&pin!==$('#unlockPinConfirm').value){error.textContent='Those PINs do not match.';error.classList.remove('hidden');return}btn.disabled=true;btn.textContent=mode==='create'?'Encrypting…':'Decrypting your plan…';try{if(mode==='create'){cryptoSalt=crypto.getRandomValues(new Uint8Array(16));cryptoKey=await deriveKey(pin,cryptoSalt);legacyData=false;await save()}else{if(!envelope?.salt||!envelope?.iv||!envelope?.data)throw new Error('missing encrypted data');const salt=fromB64(envelope.salt),candidate=await deriveKey(pin,salt),plain=await crypto.subtle.decrypt({name:'AES-GCM',iv:fromB64(envelope.iv)},candidate,fromB64(envelope.data));state={...blank(),...JSON.parse(new TextDecoder().decode(plain))};cryptoSalt=salt;cryptoKey=candidate;envelope=null}$('#pinModal').classList.remove('open');$('#pinModal').setAttribute('aria-hidden','true');document.body.style.overflow='';render();toast(mode==='create'?'Your data is encrypted':'Plan decrypted · welcome back')}catch{$('#pinModal .pin-modal').classList.remove('unlock-error');void $('#pinModal .pin-modal').offsetWidth;$('#pinModal .pin-modal').classList.add('unlock-error');error.textContent=envelope?'That PIN could not decrypt this backup. Check all six digits or restore with email.':'No encrypted backup is loaded. Restore with email first.';error.classList.remove('hidden');$('#unlockPin').select()}finally{btn.disabled=false;btn.textContent=mode==='create'?'Encrypt my data':'Unlock TruFit'}}
