  function forgotPin(){if(!confirm('Without the PIN, encrypted data cannot be recovered. Reset everything and start over?'))return;localStorage.removeItem(KEY);envelope=null;cryptoKey=null;cryptoSalt=null;legacyData=false;state=blank();$('#pinModal').classList.remove('open');document.body.style.overflow='';render();showStep(1);openModal('onboardingModal')}
  function nextStep(){const inputs=$$('input,select',$(`.form-step[data-step="${step}"]`));if(!inputs.every(i=>i.reportValidity()))return;showStep(step+1)}
