  function render(){renderToday();renderPlan();renderLog();renderProgress();nav(location.hash.slice(1)||'today',false)}
  function totals(k=dateKey()){return(state.foods[k]||[]).reduce((a,f)=>({calories:a.calories+ +f.calories,protein:a.protein+ +f.protein,carbs:a.carbs+ +f.carbs,fat:a.fat+ +f.fat}),{calories:0,protein:0,carbs:0,fat:0})}
  function schedule(){const mode=state.profile?.trainingMode||'sustainable';if(mode==='aggressive')return[[1,'A','Lower Power'],[2,'B','Upper Density'],[4,'D','Lower Volume'],[5,'E','Upper Power']];if(mode==='hybrid')return[[1,'A','Lower Power'],[2,'B','Upper Density'],[3,'C','Conditioning Grid'],[5,'D','Lower Volume'],[6,'E','Upper Power']];const n=state.profile?.trainingDays||3,days=n===2?[1,4]:n===4?[1,2,4,6]:[1,3,5];return days.map((day,i)=>[day,'ABCD'[i],`Full body ${'ABCD'[i]}`])}
  function workoutDays(){return schedule().map(x=>x[0])}
  function monday(d=new Date()){d=new Date(d);const day=d.getDay()||7;d.setHours(12,0,0,0);d.setDate(d.getDate()-day+1);return d}
  function workout(k){const item=schedule().find(x=>x[0]===(dateFrom(k).getDay()||7));if(!item)return null;const [day,key,name]=item,mode=state.profile?.trainingMode||'sustainable',isHard=mode!=='sustainable';return{key,name,hard:isHard,exercises:(isHard?hard:ex)[state.profile?.equipment||'gym'][key],duration:isHard?(key==='C'?45:55):(state.profile?.experience==='intermediate'?45:35)}}
  function weekDone(){const m=monday();return workoutDays().map(d=>dateKey(addDays(m,d-1))).filter(k=>state.workouts[k]?.complete).length}
  function streak(){let n=0;for(let i=0;i<365;i++){const k=dateKey(addDays(new Date(),-i)),active=state.foods[k]?.length||state.weights.some(w=>w.date===k)||state.workouts[k]?.complete;if(active)n++;else if(i)break}return n}
  function renderToday(){const now=new Date(),g=now.getHours()<12?'Good morning':now.getHours()<18?'Good afternoon':'Good evening';$('#dateLabel').textContent=now.toLocaleDateString(undefined,{weekday:'long',month:'short',day:'numeric'}).toUpperCase();$('#greeting').textContent=state.profile?`${g}, ${state.profile.name}`:g;$('#streakCount').textContent=streak();renderCoach();renderNutrition();renderWorkoutPreview();renderTasks()}
  function renderCoach(){const title=$('#coachTitle'),msg=$('#coachMessage'),a=$('#coachAction');if(!state.profile){title.textContent='Let’s build your plan.';msg.textContent='A few details will help TruFit make today simple and specific.';a.innerHTML='Get started <svg><use href="#i-chevron"/></svg>';return}const t=totals(),wo=workout(dateKey()),weighed=state.weights.some(w=>w.date===dateKey()),hour=new Date().getHours();if(!weighed&&hour<13){set('Start with a quick weigh-in.','One number cannot define progress, but consistent morning weigh-ins reveal the trend we can coach.','weight','Log weight')}else if(wo&&!state.workouts[dateKey()]?.complete){set(`Today: ${wo.name}.`,wo.hard?`High-output session: ${wo.duration} minutes. Do the written work only—no bonus sets—and stop if form or breathing breaks down.`:`Set aside ${wo.duration} minutes. Use controlled reps and finish each set with 1–3 good reps still available.`,'workout','See workout')}else if(t.protein<state.targets.protein*.5&&hour>=13){set('Make protein the next easy win.',`You have about ${Math.max(0,state.targets.protein-Math.round(t.protein))}g left today. Build your next meal around a lean protein.`,'food','Log a meal')}else if(t.calories>state.targets.calories){set('Nothing is ruined.','Log honestly, skip the punishment, and return to your usual plan at the next meal. The weekly average matters more than one day.','progress','View the trend')}else set('Keep today boring and repeatable.',`Aim for ${state.targets.calories.toLocaleString()} calories, get your planned movement, and choose foods you can happily eat again next week.`,'food','Log food');function set(t,m,action,label){title.textContent=t;msg.textContent=m;a.dataset.action=action;a.innerHTML=`${label} <svg><use href="#i-chevron"/></svg>`}}
  function coachAction(){if(!state.profile)return openModal('onboardingModal');const a=$('#coachAction').dataset.action;if(a==='weight')openWeight();else if(a==='workout')nav('plan');else if(a==='progress')nav('progress');else{nav('log');logTab('food')}}
  function renderNutrition(){const t=totals(),g=state.targets||{calories:0,protein:0,carbs:0,fat:0};$('#calRemaining').textContent=state.profile?Math.max(0,Math.round(g.calories-t.calories)).toLocaleString():'—';$('#calorieRing').style.setProperty('--progress',`${g.calories?clamp(t.calories/g.calories,0,1)*360:0}deg`);[['protein',t.protein,g.protein],['carbs',t.carbs,g.carbs],['fat',t.fat,g.fat]].forEach(([k,v,m])=>{$(`#${k}Now`).textContent=Math.round(v);$(`#${k}Goal`).textContent=m||'—';$(`#${k}Bar`).style.width=`${m?clamp(v/m*100,0,100):0}%`})}
