  function chart(tr){const svg=$('#weightChart');if(!tr){svg.innerHTML='<text x="300" y="115" text-anchor="middle" fill="#8b938e" font-size="13">Add two or more weigh-ins to see your trend</text>';$('#chartStart').textContent=$('#chartEnd').textContent='—';return}const data=tr.data,w=600,h=220,p=15,min=Math.min(...data.map(d=>d.weight))-1,max=Math.max(...data.map(d=>d.weight))+1,start=dateFrom(data[0].date),span=Math.max(1,(dateFrom(data.at(-1).date)-start)/864e5),x=d=>p+((dateFrom(d.date)-start)/864e5)/span*(w-p*2),y=d=>p+(max-d.weight)/(max-min)*(h-p*2),points=data.map(d=>`${x(d)},${y(d)}`).join(' '),area=`M ${x(data[0])} ${h} L ${data.map(d=>`${x(d)} ${y(d)}`).join(' L ')} L ${x(data.at(-1))} ${h} Z`;svg.innerHTML=`<defs><linearGradient id="areaGradient" x1="0" y1="0" x2="0" y2="1"><stop offset="0" stop-color="#cfe3d7" stop-opacity=".8"/><stop offset="1" stop-color="#cfe3d7" stop-opacity=".08"/></linearGradient></defs><line class="chart-grid" x1="0" y1="55" x2="600" y2="55"/><line class="chart-grid" x1="0" y1="120" x2="600" y2="120"/><line class="chart-grid" x1="0" y1="185" x2="600" y2="185"/><path class="chart-area" d="${area}"/><polyline class="chart-line" points="${points}"/>${data.map(d=>`<circle class="chart-dot" cx="${x(d)}" cy="${y(d)}" r="5"/>`).join('')}`;$('#chartStart').textContent=start.toLocaleDateString(undefined,{month:'short',day:'numeric'});$('#chartEnd').textContent=dateFrom(data.at(-1).date).toLocaleDateString(undefined,{month:'short',day:'numeric'})}
