  function exerciseKind(name,prescription){
    const n=name.toLowerCase(),rx=parsePrescription(prescription);
    if(/finisher|sprint|rower|erg|bike|treadmill|hill walk|step-up|mountain climber|conditioning|high-knee|shadow boxing|sled|battle rope|brisk|burpee/.test(n))return'conditioning';
    if(/plank|dead bug|hollow|knee raise|pallof|mobility|warm-up|carry/.test(n))return'core';
    if(state.profile?.equipment==='home'||/push-up|bodyweight|single-leg glute|towel/.test(n))return'bodyweight';
    if(rx&&rx.high<=8&&/squat|deadlift|bench|press|pull-up|row/.test(n))return'strength';
    return'hypertrophy';
  }
  function parsePrescription(text){const m=String(text).match(/(\d+)\s*[x×]\s*(\d+)(?:\s*[-–]\s*(\d+))?/i);return m?{sets:+m[1],low:+m[2],high:+(m[3]||m[2])}:null}
  function adjustedPrescription(base,type,output){
    if(output==='standard')return base;
    const rx=parsePrescription(base);
    if(output==='deload'){
      if(type==='conditioning')return`${base} · cut total work 30%`;
      if(rx)return`${Math.max(2,rx.sets-1)} x ${rx.low}${rx.high!==rx.low?`-${rx.high}`:''} · use 85–90% usual load`;
      return`${base} · easy technique pace`;
    }
    if(type==='strength')return`${base} · add no more than 2.5–5% load`;
    if(type==='conditioning')return`${base} · add 1 interval or 5% time`;
    if(rx)return`${rx.sets+1} x ${rx.low}${rx.high!==rx.low?`-${rx.high}`:''} · added volume`;
    return`${base} · add one controlled round`;
  }
  function outputGuidance(level){return{deload:'Recovery-biased: one fewer set, reduced load, and no hard finisher. Technique should feel crisp.',standard:'Planned volume and load. Finish most working sets with 1–3 reps in reserve.',push:'Capped overload: at most one extra set or 5% load. Do not use Push after poor sleep, pain, or two hard days in a row.'}[level]}
  function exerciseLogFields(type,index,log){
    if(type==='conditioning')return`<div class="exercise-log"><label>Actual<input data-exercise="${index}" data-log="actual" type="number" min="0" step="1" inputmode="decimal" value="${log.actual??''}" placeholder="0"></label><label>Unit<select data-exercise="${index}" data-log="unit"><option value="rounds" ${log.unit==='rounds'?'selected':''}>Rounds</option><option value="minutes" ${log.unit==='minutes'?'selected':''}>Minutes</option></select></label><label>Effort<select data-exercise="${index}" data-log="effort"><option value="easy" ${log.effort==='easy'?'selected':''}>Easy</option><option value="target" ${!log.effort||log.effort==='target'?'selected':''}>Target</option><option value="max" ${log.effort==='max'?'selected':''}>Max</option></select></label></div>`;
    const loadLabel=type==='bodyweight'||type==='core'?'Extra lb':'Load lb';
    return`<div class="exercise-log"><label>${loadLabel}<input data-exercise="${index}" data-log="load" type="number" min="0" step="2.5" inputmode="decimal" value="${log.load??''}" placeholder="0"></label><label>Best reps<input data-exercise="${index}" data-log="reps" type="number" min="0" step="1" inputmode="numeric" value="${log.reps??''}" placeholder="0"></label><label>RIR<select data-exercise="${index}" data-log="rir">${[0,1,2,3,4].map(v=>`<option value="${v}" ${+(log.rir??2)===v?'selected':''}>${v}</option>`).join('')}</select></label></div>`;
  }
