    const output=rec.intensity||'standard';$$('[data-output]').forEach(b=>b.classList.toggle('active',b.dataset.output===output));$('#outputValue').textContent=output.toUpperCase();$('#outputGuidance').textContent=outputGuidance(output);$('#selectedWorkoutName').textContent=w.name;$('#selectedWorkoutDuration').textContent=`${w.duration+(output==='push'?5:output==='deload'?-10:0)} min`;
